from flask import Flask, request, jsonify
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime, timedelta
import secrets
import hashlib
import time

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

limiter = Limiter(
    app=app,
    key_func=get_remote_address,
    default_limits=["200 per day", "50 per hour"],
    storage_uri="memory://"
)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(255), nullable=False)

class PasswordResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False, index=True)
    token_hash = db.Column(db.String(255), nullable=False, unique=True)
    created_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)
    used = db.Column(db.Boolean, default=False)
    ip_address = db.Column(db.String(45), nullable=True)

class PasswordResetAttempt(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    ip_address = db.Column(db.String(45), nullable=False, index=True)
    email_attempted = db.Column(db.String(120), nullable=True)
    timestamp = db.Column(db.DateTime, nullable=False, default=datetime.utcnow)
    success = db.Column(db.Boolean, default=False)

with app.app_context():
    db.create_all()

def check_ip_abuse(ip_address, window_minutes=60, max_attempts=5):
    cutoff_time = datetime.utcnow() - timedelta(minutes=window_minutes)
    attempt_count = PasswordResetAttempt.query.filter(
        PasswordResetAttempt.ip_address == ip_address,
        PasswordResetAttempt.timestamp >= cutoff_time
    ).count()
    return attempt_count >= max_attempts

def log_reset_attempt(ip_address, email=None, success=False):
    attempt = PasswordResetAttempt(
        ip_address=ip_address,
        email_attempted=email,
        success=success
    )
    db.session.add(attempt)
    db.session.commit()

def send_reset_email(email, token):
    reset_link = f"https://yourapp.com/reset-password?token={token}"
    print(f"Sending reset email to {email}: {reset_link}")
    time.sleep(0.5)

@app.route('/api/password-reset/request', methods=['POST'])
@limiter.limit("3 per hour")
def request_password_reset():
    start_time = time.time()
    ip_address = get_remote_address()
    
    if check_ip_abuse(ip_address):
        time.sleep(2)
        return jsonify({
            "message": "If an account exists with this email, a password reset link has been sent."
        }), 200
    
    data = request.get_json()
    if not data or 'email' not in data:
        return jsonify({"error": "Email is required"}), 400
    
    email = data['email'].lower().strip()
    
    if len(email) > 120 or '@' not in email:
        return jsonify({"error": "Invalid email format"}), 400
    
    user = User.query.filter_by(email=email).first()
    
    elapsed = time.time() - start_time
    if elapsed < 1.0:
        time.sleep(1.0 - elapsed)
    
    if user:
        PasswordResetToken.query.filter(
            PasswordResetToken.email == email,
            PasswordResetToken.used == False,
            PasswordResetToken.expires_at > datetime.utcnow()
        ).delete()
        
        token = secrets.token_urlsafe(32)
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        
        reset_token = PasswordResetToken(
            email=email,
            token_hash=token_hash,
            expires_at=datetime.utcnow() + timedelta(hours=1),
            ip_address=ip_address
        )
        db.session.add(reset_token)
        db.session.commit()
        
        send_reset_email(email, token)
        log_reset_attempt(ip_address, email, success=True)
    else:
        log_reset_attempt(ip_address, email, success=False)
    
    return jsonify({
        "message": "If an account exists with this email, a password reset link has been sent."
    }), 200

@app.route('/api/password-reset/verify', methods=['POST'])
@limiter.limit("10 per hour")
def verify_reset_token():
    data = request.get_json()
    if not data or 'token' not in data:
        return jsonify({"error": "Token is required"}), 400
    
    token = data['token']
    token_hash = hashlib.sha256(token.encode()).hexdigest()
    
    reset_token = PasswordResetToken.query.filter_by(
        token_hash=token_hash,
        used=False
    ).first()
    
    if not reset_token or reset_token.expires_at < datetime.utcnow():
        return jsonify({"error": "Invalid or expired token"}), 400
    
    return jsonify({
        "message": "Token is valid",
        "email": reset_token.email
    }), 200

@app.route('/api/password-reset/confirm', methods=['POST'])
@limiter.limit("10 per hour")
def confirm_password_reset():
    data = request.get_json()
    if not data or 'token' not in data or 'new_password' not in data:
        return jsonify({"error": "Token and new password are required"}), 400
    
    token = data['token']
    new_password = data['new_password']
    
    if len(new_password) < 8:
        return jsonify({"error": "Password must be at least 8 characters"}), 400
    
    token_hash = hashlib.sha256(token.encode()).hexdigest()
    
    reset_token = PasswordResetToken.query.filter_by(
        token_hash=token_hash,
        used=False
    ).first()
    
    if not reset_token or reset_token.expires_at < datetime.utcnow():
        return jsonify({"error": "Invalid or expired token"}), 400
    
    user = User.query.filter_by(email=reset_token.email).first()
    if not user:
        return jsonify({"error": "User not found"}), 404
    
    user.password_hash = hashlib.sha256(new_password.encode()).hexdigest()
    reset_token.used = True
    
    PasswordResetToken.query.filter(
        PasswordResetToken.email == reset_token.email,
        PasswordResetToken.id != reset_token.id
    ).delete()
    
    db.session.commit()
    
    return jsonify({"message": "Password has been reset successfully"}), 200

if __name__ == '__main__':
    app.run(debug=False)